func TestSearchDeploysQuotesFTSQuerySyntax(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "data.db")
	s, err := Open(dbPath)
	if err != nil {
		t.Fatalf("open: %v", err)
	}
	defer s.Close()

	items := []json.RawMessage{
		json.RawMessage(`{"id": "typed-ip", "name": "10.0.0.1"}`),
		json.RawMessage(`{"id": "typed-host", "name": "host.example.com"}`),
		json.RawMessage(`{"id": "typed-multi", "name": "error with extra words before timeout"}`),
	}
	if stored, failed, err := s.UpsertBatch("deploys", items); err != nil {
		t.Fatalf("UpsertBatch: %v", err)
	} else if failed != 0 || stored != len(items) {
		t.Fatalf("UpsertBatch stored=%d failed=%d, want stored=%d failed=0", stored, failed, len(items))
	}

	for _, query := range []string{
		"10.0.0.1",
		"host.example.com",
		"error timeout",
	} {
		results, err := s.SearchDeploys(query, 10)
		if err != nil {
			t.Fatalf("SearchDeploys(%q): %v", query, err)
		}
		if len(results) == 0 {
			t.Fatalf("SearchDeploys(%q) returned no results", query)
		}
	}
}

